export const formatRupiah = (num) => {
  if (num === 0) return 'Rp 0'
  const abs = Math.abs(num)
  const formatted = abs.toLocaleString('id-ID')
  return `${num < 0 ? '-' : ''}Rp ${formatted}`
}

